import java.nio.file.FileSystems;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Scanner;

public class PathTraversalExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a file name: ");
        String fileName = scanner.nextLine();

        Path filePath = FileSystems.getDefault().getPath("/path/to/directory", fileName).toAbsolutePath().normalize();

        if (Files.exists(filePath) && filePath.startsWith(FileSystems.getDefault().getPath("/path/to/directory").toAbsolutePath())) {
            System.out.println("File exists.");
        } else {
            System.out.println("File does not exist or is outside the allowed directory.");
        }
    }
}

